async function processStream(input) {
  const reader = input.getReader();
  const decoder = new TextDecoder();

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      const chunk = decoder.decode(value);
      yield parseChunk(chunk);
    }
  } finally {
    reader.releaseLock();
  }
}
